  collabPresetUiRegressionSupportTask:{"zh-CN": "由 OpenClaw 负责跑构建、复测页面入口、补充日志和回归验证。", "zh-TW": "由 OpenClaw 負責執行建置、複測頁面入口、補充日誌和回歸驗證。", "en": "OpenClaw runs the build, retests page entries, adds logs, and performs regression verification."},
  collabPresetDiagnosis:         {"zh-CN": "日志诊断协同", "zh-TW": "日誌診斷協同", "en": "Log diagnosis collaboration"},
  collabPresetDiagnosisLeadTask: {"zh-CN": "由 OpenClaw 负责抓取运行状态、日志、接口响应和系统环境信息。", "zh-TW": "由 OpenClaw 負責抓取執行狀態、日誌、介面回應和系統環境資訊。", "en": "OpenClaw collects runtime status, logs, API responses, and system environment details."},
  collabPresetDiagnosisSupportTask:{"zh-CN": "由 Hermes 负责基于证据链做根因分析、假设收敛和修复建议。", "zh-TW": "由 Hermes 負責基於證據鏈做根因分析、假設收斂和修復建議。", "en": "Hermes performs evidence-based root-cause analysis, hypothesis narrowing, and fix recommendations."},
  collabPresetDocPlan:           {"zh-CN": "方案/文档协同", "zh-TW": "方案/文件協同", "en": "Plan/document collaboration"},
