  collabManualTemplate:          {"zh-CN": "# 双引擎协同任务\n\n[任务目标]\n{goal}\n\n[建议分配]\n- 主导引擎: {lead}\n- 协作引擎: {peer}\n\n[主导任务]\n- {leadTask}\n\n[协作任务]\n- {supportTask}\n\n[执行策略]\n- 自动迭代: {autoIterate}\n- 最大轮数: {maxRounds}\n\n[主导引擎职责]\n- 拆解任务\n- 汇总结论\n- 输出最终结果\n\n[协作引擎职责]\n- 补充分析\n- 交叉验证\n- 处理分支子任务\n\n[执行规则]\n- 用户填写的主导引擎 / 协作引擎 / 主导任务 / 协作任务优先级最高\n- 必须明确谁主导、谁协作\n- 先给出执行计划，再开始执行\n- 最终只输出一份合并后的结果\n\n[最终输出要求]\n- 结果必须包含“执行计划 / 协同分工 / 最终结论”三个部分", "zh-TW": "# 雙引擎協同任務\n\n[任務目標]\n{goal}\n\n[建議分配]\n- 主導引擎: {lead}\n- 協作引擎: {peer}\n\n[主導任務]\n- {leadTask}\n\n[協作任務]\n- {supportTask}\n\n[執行策略]\n- 自動迭代: {autoIterate}\n- 最大輪數: {maxRounds}\n\n[主導引擎職責]\n- 拆解任務\n- 彙整結論\n- 輸出最終結果\n\n[協作引擎職責]\n- 補充分析\n- 交叉驗證\n- 處理分支子任務\n\n[執行規則]\n- 使用者填寫的主導引擎 / 協作引擎 / 主導任務 / 協作任務優先級最高\n- 必須明確誰主導、誰協作\n- 先給出執行計畫，再開始執行\n- 最終只輸出一份合併後的結果\n\n[最終輸出要求]\n- 結果必須包含「執行計畫 / 協同分工 / 最終結論」三個部分", "en": "# Dual-engine collaboration task\n\n[Goal]\n{goal}\n\n[Suggested assignment]\n- Lead engine: {lead}\n- Support engine: {peer}\n\n[Lead task]\n- {leadTask}\n\n[Support task]\n- {supportTask}\n\n[Execution strategy]\n- Auto iterate: {autoIterate}\n- Max rounds: {maxRounds}\n\n[Lead engine responsibilities]\n- Break down the task\n- Synthesize findings\n- Produce the final result\n\n[Support engine responsibilities]\n- Add analysis\n- Cross-check\n- Handle branch subtasks\n\n[Execution rules]\n- User-provided lead/support engines and tasks have the highest priority\n- Clearly state who leads and who supports\n- Provide the plan before execution\n- Output only one merged result\n\n[Final output requirements]\n- Include three sections: Execution plan / Collaboration split / Final conclusion"},
  collabManualTemplateCompact:   {"zh-CN": "# 双引擎协同任务\n\n[任务目标]\n{goal}\n\n[建议分配]\n- 主导引擎: {lead}\n- 协作引擎: {peer}\n\n[主导任务]\n- {leadTask}\n\n[协作任务]\n- {supportTask}\n\n[执行策略]\n- 自动迭代: {autoIterate}\n- 最大轮数: {maxRounds}", "zh-TW": "# 雙引擎協同任務\n\n[任務目標]\n{goal}\n\n[建議分配]\n- 主導引擎: {lead}\n- 協作引擎: {peer}\n\n[主導任務]\n- {leadTask}\n\n[協作任務]\n- {supportTask}\n\n[執行策略]\n- 自動迭代: {autoIterate}\n- 最大輪數: {maxRounds}", "en": "# Dual-engine collaboration task\n\n[Goal]\n{goal}\n\n[Suggested assignment]\n- Lead engine: {lead}\n- Support engine: {peer}\n\n[Lead task]\n- {leadTask}\n\n[Support task]\n- {supportTask}\n\n[Execution strategy]\n- Auto iterate: {autoIterate}\n- Max rounds: {maxRounds}"},
  collabAutoModeGeneral:         {"zh-CN": "通用任务", "zh-TW": "通用任務", "en": "General task"},
  collabAutoModeCode:            {"zh-CN": "代码/工程任务", "zh-TW": "程式碼/工程任務", "en": "Code/engineering task"},
  collabAutoModeDocs:            {"zh-CN": "文档/多语言任务", "zh-TW": "文件/多語言任務", "en": "Docs/localization task"},
  collabAutoModeDiagnosis:       {"zh-CN": "排障/诊断任务", "zh-TW": "排障/診斷任務", "en": "Troubleshooting/diagnosis task"},
  collabAutoExtraGeneral:        {"zh-CN": "请按通用复杂任务的方式，自动判断主导/协作关系并分工执行。", "zh-TW": "請按通用複雜任務的方式，自動判斷主導/協作關係並分工執行。", "en": "Handle this as a general complex task: decide the lead/support split automatically and execute with clear roles."},
  collabAutoExtraCode:           {"zh-CN": "优先让更擅长工程落地的引擎主导，让协作引擎负责代码审查、边界条件和回归验证。", "zh-TW": "優先讓更擅長工程落地的引擎主導，讓協作引擎負責程式碼審查、邊界條件和回歸驗證。", "en": "Prefer the engine better at engineering execution as lead; the support engine handles code review, edge cases, and regression checks."},
  collabAutoExtraDocs:           {"zh-CN": "优先让更擅长结构化表达的引擎主导，让协作引擎负责术语统一、漏项检查和风格校正。", "zh-TW": "優先讓更擅長結構化表達的引擎主導，讓協作引擎負責術語統一、漏項檢查和風格校正。", "en": "Prefer the engine better at structured writing as lead; the support engine checks terminology, omissions, and style."},
  collabAutoExtraDiagnosis:      {"zh-CN": "优先让更擅长诊断链路的引擎主导，让协作引擎负责交叉验证、假设枚举和根因收敛。", "zh-TW": "優先讓更擅長診斷鏈路的引擎主導，讓協作引擎負責交叉驗證、假設枚舉和根因收斂。", "en": "Prefer the engine better at diagnosis as lead; the support engine cross-checks, enumerates hypotheses, and narrows root cause."},
