  collabAutoGeneralRiskOverlap:  {"zh-CN": "避免主导与协作职责重叠", "zh-TW": "避免主導與協作職責重疊", "en": "Avoid overlapping lead/support responsibilities"},
  collabAutoGeneralRiskConflict: {"zh-CN": "如结论不一致，必须说明冲突点", "zh-TW": "如結論不一致，必須說明衝突點", "en": "If conclusions differ, explain the conflict"},
  collabAutoGeneralRiskMerged:   {"zh-CN": "最终只保留一份合并结果", "zh-TW": "最終只保留一份合併結果", "en": "Keep only one merged final result"},
  collabAutoCodeLeadImplement:   {"zh-CN": "负责代码修改与实现路径选择", "zh-TW": "負責程式碼修改與實作路徑選擇", "en": "Own code changes and implementation choices"},
  collabAutoCodeLeadDebug:       {"zh-CN": "推进构建、调试与修复主线", "zh-TW": "推進建置、除錯與修復主線", "en": "Drive build, debugging, and fixes"},
