  collabAutoCodePeerEdges:       {"zh-CN": "检查边界条件与潜在副作用", "zh-TW": "檢查邊界條件與潛在副作用", "en": "Check edge cases and side effects"},
  collabAutoCodePeerRegression:  {"zh-CN": "补充回归验证建议", "zh-TW": "補充回歸驗證建議", "en": "Add regression validation suggestions"},
  collabAutoCodeRiskRootCause:   {"zh-CN": "避免只修表面现象而遗漏根因", "zh-TW": "避免只修表面現象而遺漏根因", "en": "Avoid fixing symptoms while missing root cause"},
  collabAutoCodeRiskBuild:       {"zh-CN": "避免改动破坏现有构建链路", "zh-TW": "避免改動破壞現有建置鏈路", "en": "Avoid breaking the existing build flow"},
  collabAutoCodeRiskValidation:  {"zh-CN": "输出中必须说明验证范围", "zh-TW": "輸出中必須說明驗證範圍", "en": "State the validation scope in the output"},
