  collabAutoDocsLeadNarrative:   {"zh-CN": "统一主叙事与输出顺序", "zh-TW": "統一主敘事與輸出順序", "en": "Unify narrative and output order"},
  collabAutoDocsLeadDraft:       {"zh-CN": "完成最终文案定稿", "zh-TW": "完成最終文案定稿", "en": "Finalize the copy"},
