  collabAutoDocsPeerStyle:       {"zh-CN": "修正语言风格与多语言偏差", "zh-TW": "修正語言風格與多語言偏差", "en": "Correct style and localization drift"},
  collabAutoDocsRiskTerms:       {"zh-CN": "避免术语前后不一致", "zh-TW": "避免術語前後不一致", "en": "Avoid inconsistent terminology"},
  collabAutoDocsRiskMeaning:     {"zh-CN": "避免翻译语义漂移", "zh-TW": "避免翻譯語義漂移", "en": "Avoid translation meaning drift"},
  collabAutoDocsRiskNames:       {"zh-CN": "如改动文档名称，需注意历史语义与品牌影响", "zh-TW": "如改動文件名稱，需注意歷史語義與品牌影響", "en": "If document names change, consider historical meaning and branding"},
  collabAutoDiagnosisLeadHypothesis:{"zh-CN": "负责建立问题假设", "zh-TW": "負責建立問題假設", "en": "Build problem hypotheses"},
  collabAutoDiagnosisLeadLogs:   {"zh-CN": "推进日志/链路诊断主线", "zh-TW": "推進日誌/鏈路診斷主線", "en": "Drive log and flow diagnosis"},
  collabAutoDiagnosisLeadRootCause:{"zh-CN": "收敛根因并给出修复方向", "zh-TW": "收斂根因並給出修復方向", "en": "Narrow root cause and propose fixes"},
  collabAutoDiagnosisPeerAlternatives:{"zh-CN": "枚举替代假设", "zh-TW": "枚舉替代假設", "en": "List alternative hypotheses"},
